class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id', '')
        self.event_type = data.get('event_type', '')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account', '')
        self.receiver_account = data.get('receiver_account', '')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, type={self.event_type}, "
            f"amount={self.amount} {self.currency}, status={self.status})"
        )


class TransactionResult:
    """Result of processing a transaction event."""

    def __init__(self, transaction_id: str, success: bool, message: str = '',
                 details: Optional[Dict] = None):
        self.transaction_id = transaction_id
        self.success = success
        self.message = message
        self.details = details or {}
        self.processed_at = datetime.utcnow().isoformat()

    def __repr__(self):
        status = "SUCCESS" if self.success else "FAILED"
        return f"TransactionResult({self.transaction_id}: {status} - {self.message})"


class FraudDetectionService:
    """Simple fraud detection service for transaction validation."""

    HIGH_AMOUNT_THRESHOLD = 10000.0
    SUSPICIOUS_CURRENCIES = {'XMR', 'DASH'}

    @staticmethod
    def check_transaction(event: TransactionEvent) -> Dict[str, Any]:
        risk_score = 0.0
        flags = []

        if event.amount > FraudDetectionService.HIGH_AMOUNT_THRESHOLD:
            risk_score += 0.4
            flags.append('high_amount')

        if event.currency in FraudDetectionService.SUSPICIOUS_CURRENCIES:
            risk_score += 0.3
            flags.append('suspicious_currency')

        if event.sender_account == event.receiver_account:
            risk_score += 0.2
            flags.append('self_transfer')

        metadata = event.metadata
        if metadata.get('country_mismatch', False):
            risk_score += 0.3
            flags.append('country_mismatch')

        if metadata.get('velocity_exceeded', False):
            risk_score += 0.25
            flags.append('velocity_exceeded')

        return {
            'risk_score': min(risk_score, 1.0),
            'flags': flags,
            'is_suspicious': risk_score >= 0.5,
            'requires_review': 0.3 <= risk_score < 0.5,
            'approved': risk_score < 0.3
        }


class TransactionHandlerRegistry:
    """Registry for dynamic message handlers based on event types."""

    def __init__(self):
        self._handlers: Dict[str, Callable[[TransactionEvent], TransactionResult]] = {}
        self._pre_processors: list = []
        self._post_processors: list = []

    def register_handler(self, event_type: str, handler: Callable[[TransactionEvent], TransactionResult]):
        """Register a handler for a specific event type."""
        self._handlers[event_type] = handler
        logger.info(f"Registered handler for event type: {event_type}")

    def register_pre_processor(self, processor: Callable[[TransactionEvent], TransactionEvent]):
        """Register a pre-processor that runs before the main handler."""
        self._pre_processors.append(processor)

    def register_post_processor(self, processor: Callable[[TransactionResult], TransactionResult]):
        """Register a post-processor that runs after the main handler."""
        self._post_processors.append(processor)

    def handle(self, event: TransactionEvent) -> TransactionResult:
        """Route and handle an event using the registered handler."""
        # Run pre-processors
        for pre_proc in self._pre_processors:
            event = pre_proc(event)

        handler = self._handlers.get(event.event_type)
        if handler is None:
            logger.warning(f"No handler registered for event type: {event.event_type}")
            result = TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message=f"No handler for event type: {event.event_type}"
            )
        else:
            try:
                result = handler(event)
            except Exception as e:
                logger.error(f"Error handling event {event.transaction_id}: {e}", exc_info=True)
                result = TransactionResult(
                    transaction_id=event.transaction_id,
                    success=False,
                    message=f"Handler error: {str(e)}"
                )

        # Run post-processors
        for post_proc in self._post_processors:
            result = post_proc(result)

        return result

    def get_registered_types(self) -> list:
        return list(self._handlers.keys())


