def handle_payment(event: TransactionEvent) -> TransactionResult:
    """Handle payment transaction events."""
    logger.info(f"Processing payment: {event.transaction_id} for {event.amount} {event.currency}")

    # Fraud check
    fraud_result = FraudDetectionService.check_transaction(event)

    if fraud_result['is_suspicious']:
        logger.warning(f"Suspicious payment detected: {event.transaction_id}, flags: {fraud_result['flags']}")
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Payment flagged as suspicious",
            details={'fraud_check': fraud_result, 'action': 'blocked'}
        )

    if fraud_result['requires_review']:
        logger.info(f"Payment requires manual review: {event.transaction_id}")
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message="Payment queued for manual review",
            details={'fraud_check': fraud_result, 'action': 'review'}
        )

    # Process the payment
    logger.info(f"Payment approved: {event.transaction_id}")
    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Payment processed successfully",
        details={
            'fraud_check': fraud_result,
            'action': 'approved',
            'sender': event.sender_account,
            'receiver': event.receiver_account,
            'amount': event.amount,
            'currency': event.currency
        }
    )


def handle_transfer(event: TransactionEvent) -> TransactionResult:
    """Handle fund transfer events."""
    logger.info(f"Processing transfer: {event.transaction_id}")

    if not event.sender_account or not event.receiver_account:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Transfer requires both sender and receiver accounts"
        )

    if event.amount <= 0:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Transfer amount must be positive"
        )

    fraud_result = FraudDetectionService.check_transaction(event)

    if fraud_result['is_suspicious']:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Transfer blocked by fraud detection",
            details={'fraud_check': fraud_result}
        )

    logger.info(
        f"Transfer executed: {event.amount} {event.currency} "
        f"from {event.sender_account} to {event.receiver_account}"
    )
    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Transfer completed successfully",
        details={
            'from': event.sender_account,
            'to': event.receiver_account,
            'amount': event.amount,
            'currency': event.currency
        }
    )


def handle_refund(event: TransactionEvent) -> TransactionResult:
    """Handle refund transaction events."""
    logger.info(f"Processing refund: {event.transaction_id}")

    original_txn = event.metadata.get('original_transaction_id')
    if not original_txn:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Refund requires original_transaction_id in metadata"
        )

    refund_reason = event.metadata.get('reason', 'No reason provided')

    logger.info(
        f"Refund processed for original txn {original_txn}: "
        f"{event.amount} {event.currency}, reason: {refund_reason}"
    )
    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Refund processed successfully",
        details={
            'original_transaction': original_txn,
            'refund_amount': event.amount,
            'reason': refund_reason
        }
    )


def handle_withdrawal(event: TransactionEvent) -> TransactionResult:
    """Handle withdrawal events."""
    logger.info(f"Processing withdrawal: {event.transaction_id}")

    if event.amount <= 0:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Withdrawal amount must be positive"
        )

    daily_limit = event.metadata.get('daily_limit', 5000.0)
    if event.amount > daily_limit:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message=f"Withdrawal exceeds daily limit of {daily_limit} {event.currency}",
            details={'requested': event.amount, 'limit': daily_limit}
        )

    fraud_result = FraudDetectionService.check_transaction(event)
    if fraud_result['is_suspicious']:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Withdrawal blocked by fraud detection",
            details={'fraud_check': fraud_result}
        )

    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Withdrawal processed successfully",
        details={'account': event.sender_account, 'amount': event.amount}
    )


def handle_deposit(event: TransactionEvent) -> TransactionResult:
    """Handle deposit events."""
    logger.info(f"Processing deposit: {event.transaction_id}")

    if event.amount <= 0:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Deposit amount must be positive"
        )

    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Deposit processed successfully",
        details={'account': event.receiver_account, 'amount': event.amount}
    )


def handle_account_update(event: TransactionEvent) -> TransactionResult:
    """Handle account update events."""
    logger.info(f"Processing account update: {event.transaction_id}")

    update_fields = event.metadata.get('update_fields', {})
    if not update_fields:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message="Account update requires update_fields in metadata"
        )

    return TransactionResult(
        transaction_id=event.transaction_id,
        success=True,
        message="Account updated successfully",
        details={'updated_fields': list(update_fields.keys())}
    )


