def enrich_event(event: TransactionEvent) -> TransactionEvent:
    """Pre-processor to enrich event with additional data."""
    event.metadata['processed_timestamp'] = datetime.utcnow().isoformat()
    event.metadata['processor_version'] = '1.0.0'
    return event


def audit_result(result: TransactionResult) -> TransactionResult:
    """Post-processor to log audit trail."""
    logger.info(f"AUDIT: {result}")
    return result


class FinancialTransactionConsumer:
    """Kafka consumer for processing financial transaction events."""

    def __init__(
        self,
        bootstrap_servers: str = 'localhost:9092',
        topics: Optional[list] = None,
        group_id: str = 'transaction-processor-group',
        auto_offset_reset: str = 'earliest',
        enable_auto_commit: bool = False,
        max_poll_records: int = 100,
        consumer_timeout_ms: int = -1,
        **kwargs
    ):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics or ['financial-transactions']
        self.group_id = group_id
        self.running = False
        self._consumer = None
        self._processed_count = 0
        self._error_count = 0

        # Initialize handler registry
        self.registry = TransactionHandlerRegistry()
        self._register_default_handlers()

        # Kafka consumer configuration
        self._consumer_config = {
            'bootstrap_servers': bootstrap_servers,
            'group_id': group_id,
            'auto_offset_reset': auto_offset_reset,
            'enable_auto_commit': enable_auto_commit,
            'max_poll_records': max_poll_records,
            'value_deserializer': self._deserialize_message,
            'key_deserializer': lambda k: k.decode('utf-8') if k else None,
            **kwargs
        }

        if consumer_timeout_ms > 0:
            self._consumer_config['consumer_timeout_ms'] = consumer_timeout_ms

    def _register_default_handlers(self):
        """Register all default transaction handlers."""
        self.registry.register_handler('payment', handle_payment)
        self.registry.register_handler('transfer', handle_transfer)
        self.registry.register_handler('refund', handle_refund)
        self.registry.register_handler('withdrawal', handle_withdrawal)
        self.registry.register_handler('deposit', handle_deposit)
        self.registry.register_handler('account_update', handle_account_update)

        # Register pre/post processors
        self.registry.register_pre_processor(enrich_event)
        self.registry.register_post_processor(audit_result)

    def register_handler(self, event_type: str, handler: Callable):
        """Register a custom handler for a specific event type."""
        self.registry.register_handler(event_type, handler)

    @staticmethod
    def _deserialize_message(raw_message: bytes) -> Dict[str, Any]:
        """Deserialize message from bytes to dict."""
        try:
            return json.loads(raw_message.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"Failed to deserialize message: {e}")
            return {'_deserialization_error': str(e), '_raw': raw_message.hex()}

    def _create_consumer(self):
        """Create and return a KafkaConsumer instance."""
        try:
            consumer = KafkaConsumer(**self._consumer_config)
            consumer.subscribe(self.topics)
            logger.info(
                f"Kafka consumer created. Subscribed to topics: {self.topics}, "
                f"group: {self.group_id}"
            )
            return consumer
        except KafkaError as e:
            logger.error(f"Failed to create Kafka consumer: {e}")
            raise

    def _process_message(self, message) -> Optional[TransactionResult]:
        """Process a single Kafka message."""
        data = message.value

        if '_deserialization_error' in data:
            logger.error(
                f"Skipping message due to deserialization error: "
                f"{data['_deserialization_error']}"
            )
            self._error_count += 1
            return None

        event = TransactionEvent(data)
        logger.info(
            f"Received event: {event} from topic={message.topic}, "
            f"partition={message.partition}, offset={message.offset}"
        )

        result = self.registry.handle(event)
        self._processed_count += 1

        if not result.success:
            self._error_count += 1

        return result

    def start(self):
        """Start consuming and processing messages."""
        self._consumer = self._create_consumer()
        self.running = True

        # Set up graceful shutdown
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)

        logger.info("Starting transaction consumer...")
        logger.info(f"Registered event types: {self.registry.get_registered_types()}")

        try:
            while self.running:
                message_batch = self._consumer.poll(timeout_ms=1000)

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        try:
                            result = self._process_message(message)
                            if result:
                                logger.info(f"Result: {result}")
                        except Exception as e:
                            logger.error(
                                f"Unexpected error processing message at "
                                f"offset {message.offset}: {e}",
                                exc_info=True
                            )
                            self._error_count += 1

                # Manual commit after processing batch
                if message_batch:
                    try:
                        self._consumer.commit()
                    except KafkaError as e:
                        logger.error(f"Failed to commit offsets: {e}")

        except Exception as e:
            logger.error(f"Consumer error: {e}", exc_info=True)
        finally:
            self.stop()

    def stop(self):
        """Stop the consumer gracefully."""
        self.running = False
        if self._consumer:
            try:
                self._consumer.commit()
            except Exception:
                pass
            self._consumer.close()
            logger.info(
                f"Consumer stopped. Processed: {self._processed_count}, "
                f"Errors: {self._error_count}"
            )

    def _signal_handler(self, signum, frame):
        """Handle shutdown signals gracefully."""
        logger.info(f"Received signal {signum}. Shutting down...")
        self.running = False

    def get_stats(self) -> Dict[str, Any]:
        """Return consumer processing statistics."""
        return {
            'processed_count': self._processed_count,
            'error_count': self._error_count,
            'success_rate': (
                (self._processed_count - self._error_count) / self._processed_count * 100
                if self._processed_count > 0 else 0
            ),
            'topics': self.topics,
            'group_id': self.group_id,
            'registered_handlers': self.registry.get_registered_types()
        }


