def run_offline_demo():
    """Run a demo without an actual Kafka broker to showcase the processing logic."""
    logger.info("=" * 60)
    logger.info("Running offline demo (no Kafka broker required)")
    logger.info("=" * 60)

    consumer = FinancialTransactionConsumer()

    # Register a custom handler
    def handle_custom_event(event: TransactionEvent) -> TransactionResult:
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message="Custom event processed"
        )

    consumer.register_handler('custom_event', handle_custom_event)

    sample_messages = create_sample_messages()

    for msg_data in sample_messages:
        event = TransactionEvent(msg_data)
        # Run through pre-processors
        event = enrich_event(event)
        result = consumer.registry.handle(event)
        logger.info(f"  -> {result}")
        logger.info(f"     Details: {result.details}")
        logger.info("")

    stats = consumer.get_stats()
    logger.info(f"Processing stats: {json.dumps(stats, indent=2)}")


